import{_ as C,o as g,c as B,a0 as E}from"./chunks/framework.RL10UjUE.js";const a="data:image/png;base64,",i=JSON.parse('{"title":"ブックマークのインポート","description":"","frontmatter":{},"headers":[],"relativePath":"guide/import.md","filePath":"guide/import.md"}'),I={name:"guide/import.md"};function Q(r,A,e,o,s,w){return g(),B("div",null,[...A[0]||(A[0]=[E('<h1 id="ブックマークのインポート" tabindex="-1">ブックマークのインポート <a class="header-anchor" href="#ブックマークのインポート" aria-label="Permalink to &quot;ブックマークのインポート&quot;">​</a></h1><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><p>各ブラウザのエクスポート機能で HTML ファイルを生成し、それを本ツールに取り込みます。</p><h2 id="各ブラウザのエクスポート手順" tabindex="-1">各ブラウザのエクスポート手順 <a class="header-anchor" href="#各ブラウザのエクスポート手順" aria-label="Permalink to &quot;各ブラウザのエクスポート手順&quot;">​</a></h2><h3 id="google-chrome" tabindex="-1">Google Chrome <a class="header-anchor" href="#google-chrome" aria-label="Permalink to &quot;Google Chrome&quot;">​</a></h3><ol><li>メニュー → ブックマーク → ブックマークマネージャ（<code>Cmd + Option + B</code>）</li><li>右上の <code>⋯</code> → ブックマークをエクスポート</li><li><code>bookmarks.html</code> がダウンロードされます</li></ol><h3 id="mozilla-firefox" tabindex="-1">Mozilla Firefox <a class="header-anchor" href="#mozilla-firefox" aria-label="Permalink to &quot;Mozilla Firefox&quot;">​</a></h3><ol><li>ライブラリ（<code>Cmd + Shift + O</code>）→ インポートとバックアップ → HTML 形式でエクスポート</li><li><code>bookmarks.html</code> がダウンロードされます</li></ol><h3 id="safari" tabindex="-1">Safari <a class="header-anchor" href="#safari" aria-label="Permalink to &quot;Safari&quot;">​</a></h3><ol><li>ファイル → ブックマークを書き出す</li><li><code>Safari Bookmarks.html</code> がダウンロードされます</li></ol><h3 id="microsoft-edge" tabindex="-1">Microsoft Edge <a class="header-anchor" href="#microsoft-edge" aria-label="Permalink to &quot;Microsoft Edge&quot;">​</a></h3><p>Chrome と同様の Chromium ベースです。</p><ol><li>メニュー → お気に入り → お気に入りの管理 → <code>⋯</code> → お気に入りをエクスポート</li><li><code>bookmarks.html</code> がダウンロードされます</li></ol><h2 id="インポート実行" tabindex="-1">インポート実行 <a class="header-anchor" href="#インポート実行" aria-label="Permalink to &quot;インポート実行&quot;">​</a></h2><ol><li>アプリのメニューから <strong>ファイル → インポート</strong> を選択</li><li>先ほどエクスポートした HTML ファイルを選択</li><li>インポートが完了すると、ブックマーク一覧が更新されます</li></ol><p><img src="'+a+'" alt="インポート実行画面"></p><h2 id="注意点" tabindex="-1">注意点 <a class="header-anchor" href="#注意点" aria-label="Permalink to &quot;注意点&quot;">​</a></h2><ul><li>同じ URL のブックマークが既に存在する場合は、重複検出機能で確認できます（重複タブを参照）</li><li>複数のブラウザから順番にインポートすることで、すべてのブックマークを一元管理できます</li><li>HTML ファイル内のフォルダ構造はタグとしてインポートされます</li></ul>',18)])])}const m=C(I,[["render",Q]]);export{i as __pageData,m as default};
